using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    // --- Happy-path ---

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeIds()
    {
        var r1 = await _gateway.ChargeAsync("tok_visa", 10m);
        var r2 = await _gateway.ChargeAsync("tok_visa", 10m);

        Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
    }

    // --- Amount validation ---

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_visa", -5m));
    }

    // --- Token validation ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_NullOrEmptyToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    // --- Declined card ---

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 100m);

        Assert.IsFalse(result.Success);
    }
}

[TestClass]
public sealed class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    // --- Happy-path ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_visa", 25m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    // --- ChargeId validation ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    // --- Double-refund ---

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_visa", 50m);
        await _gateway.RefundAsync(charge.ChargeId);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }
}

